 1	import * as React from 'react';
 2	import { Chip } from '@patternfly/react-core';
 3	import { kialiStyle } from 'styles/StyleUtils';
 4	import { FILTERING_SELECTED_TOOLTIP, wizardTooltip } from '../WizardHelp';
 5	
 6	type Props = {
 7	  filters: string[];
 8	  onRemoveFilter: (filter: string) => void;
 9	};
10	
11	const labelContainerStyle = kialiStyle({
12	  marginTop: 20,
13	  height: 40
14	});
15	
16	const remove = kialiStyle({
17	  cursor: 'not-allowed'
18	});
19	
20	export class K8sFilters extends React.Component<Props> {
21	  render() {
22	    const filters: any[] = this.props.filters.map((filter, index) => (
23	      <span key={filter + '-' + index} data-test={filter} className={remove}>
24	        <Chip onClick={() => this.props.onRemoveFilter(filter)} isOverflowChip={true}>
25	          {filter}
26	        </Chip>{' '}
27	      </span>
28	    ));
29	    return (
30	      <div className={labelContainerStyle}>
31	        <span
32	          style={{
33	            marginRight: '32px'
34	          }}
35	        >
36	          Filtering selected
37	          {wizardTooltip(FILTERING_SELECTED_TOOLTIP)}
38	        </span>
39	        {filters.length > 0 ? filters : <b>No Request Filter</b>}
40	      </div>
41	    );
42	  }
43	}

